# filename: services/task.py
from app import db
from app.models import Task
from app.services.auth import decode_token

def get_tasks(token):
    try:
        user_id = decode_token(token)['user_id']
        tasks = Task.query.filter_by(user_id=user_id).all()
        return tasks
    except Exception as e:
        return str(e)

def create_task(token, name, description, due_date):
    try:
        user_id = decode_token(token)['user_id']
        task = Task(name=name, description=description, due_date=due_date, user_id=user_id)
        db.session.add(task)
        db.session.commit()
        return task
    except Exception as e:
        return str(e)

def update_task(token, task_id, name, description, due_date):
    try:
        user_id = decode_token(token)['user_id']
        task = Task.query.get(task_id)
        if task.user_id == user_id:
            task.name = name
            task.description = description
            task.due_date = due_date
            db.session.commit()
            return task
        else:
            return 'Unauthorized'
    except Exception as e:
        return str(e)

def delete_task(token, task_id):
    try:
        user_id = decode_token(token)['user_id']
        task = Task.query.get(task_id)
        if task.user_id == user_id:
            db.session.delete(task)
            db.session.commit()
            return 'Task deleted'
        else:
            return 'Unauthorized'
    except Exception as e:
        return str(e)
