# filename: controllers/task_controller.py
from flask import request, jsonify
from app import app
from app.services.task import get_tasks, create_task, update_task, delete_task
from app.repositories.task_repository import TaskRepository

task_repository = TaskRepository()

@app.route('/tasks', methods=['GET'])
def get_tasks_endpoint():
    token = request.headers.get('Authorization')
    tasks = task_repository.get_tasks(token)
    return jsonify([task.name for task in tasks])

@app.route('/tasks', methods=['POST'])
def create_task_endpoint():
    token = request.headers.get('Authorization')
    data = request.json
    task = task_repository.create_task(token, data['name'], data['description'], data['due_date'])
    return jsonify(task)

@app.route('/tasks/<int:task_id>', methods=['PUT'])
def update_task_endpoint(task_id):
    token = request.headers.get('Authorization')
    data = request.json
    task = task_repository.update_task(token, task_id, data['name'], data['description'], data['due_date'])
    return jsonify(task)

@app.route('/tasks/<int:task_id>', methods=['DELETE'])
def delete_task_endpoint(task_id):
    token = request.headers.get('Authorization')
    task = task_repository.delete_task(token, task_id)
    return jsonify(task)
